-- ─────────────────────────────────────────────────────────────
-- 016_import_dre_jan_abr_2026.sql
-- Importa despesas e faturamento de jan-abr/2026 (gerado por script).
-- Total despesas: 347 — inferidas: 45 — sem código: 39
-- ─────────────────────────────────────────────────────────────

-- 1) Permitir vendedor_id NULL em comissoes_recebidas (faturamento DRE não é por vendedor)
alter table public.comissoes_recebidas alter column vendedor_id drop not null;

-- 2) Coluna valor_previsto em despesas (planejado da planilha)
alter table public.financeiro_despesas add column if not exists valor_previsto numeric(12,2);

-- 3) Categorias (cria se não existir; nome conforme primeira ocorrência)

-- 4) Despesas
-- Idempotência: deleta lançamentos previamente importados via origem=importacao_dre_2026
alter table public.financeiro_despesas add column if not exists origem_import text;
delete from public.financeiro_despesas where origem_import = 'dre_2026_jan_abr';


-- 5) Faturamento (comissoes_recebidas)
delete from public.comissoes_recebidas where origem = 'importacao' and obs = 'DRE 2026 jan-abr import';


-- Fim do import